import{c as i,Q as o,j as a,m as r}from"./chunks/framework.hhGiamYR.js";const u=JSON.parse('{"title":"第9章","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/scholarship/najemy-power/09-ch09.md","filePath":"research/machiavelli/scholarship/najemy-power/09-ch09.md"}'),n={name:"research/machiavelli/scholarship/najemy-power/09-ch09.md"};function l(t,e,c,s,p,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="第9章" tabindex="-1">第9章 <a class="header-anchor" href="#第9章" aria-label="Permalink to &quot;第9章&quot;">​</a></h1><p>第九章 诗歌与政治/392 圣卡夏诺的科里东/392 文本中的变形记/400</p><p>结语《李维史论》的诗人们/419</p><p>索引1马基雅维利著作/437 索引2人名、地名、术语/438</p><p>译后记/456</p><p>前 言</p><p>[ix] 本研究是对马基雅维利与韦托里1513一1515年间书信 的解读,我尝试将这一解读工作置于马基雅维利成为一名作家和 政治理论家,及其发生转变的语境中。某些潜在的读者或许会感 到好奇,我为何决意对这些相当知名且已多次出版的书信投入大 量精力,况且从档案或者手稿里我也没有什么新的发现。马基雅 维利专家们以其专业与耐心,已经苦心孤诣地提高了文本的精确 度,测定了书信的年代,并且确定了其中明指和暗指的人物、事件 与文本。其中某些信件,最著名的当属1513年12月10日的那封 信,已经得到了相当多的深刻分析与解读。然而,尽管已经存在所 有此类工作,对具体的篇目、单独的信件、特定的主题做了精彩的 处理,但是一直都没有能将这场通信作为一个整体加以阐释的研 究出现。 本项研究的主要目的首先是表明为什么以及在何种意义上马 基雅维利与韦托里1513一1515年间的书信可以被视作一个有待 阐释的整体(甚至马基雅维利与韦托里本人是如何逐渐这样看待 它们的),其次是要表明解读这些书信何以能够对阐释马基雅维 利的主要著作这一更大的目标有所助益。 有很多理由可以解释为何缺乏对他们的通信的全面阐释。第</p><p>2 权力与欲望- 基雅维利与韦托里1513—1515年通信研究 一个或许也是最明显的理由是，这些书信本身在一般意义上并不 构成一个单一的文本。在1513年之前，马基雅维利和韦托里之间 当然偶尔也有书信往来(一如一封1510年发自韦托里的信中所表 明的那样),而到了1520年代，他们之间的书信往来又变得相当频 繁。在这样一个跨越几乎20年的通信时段里，乍看上去很难发现 为何仅仅这两年能够或者应该被视为一个独特的单元。另外一个 理由则不仅关涉两位作者，还(合理地)关涉读者们，他们在阅读 时带有各种不同的假设与期待。 谁都(以这样或那样的方式)知道马基雅维利，而只有专精于 意大利文艺复兴历史和文学的专家们听说过韦托里，甚至其中很 多人也只认为他不过是马基雅维利的朋友和有书信往来的人。对 很多人而言，这看起来是一种不平衡的合著关系，这种不平衡如此 明显，以至于他们也没什么兴趣认真对待韦托里和他的书信，甚或 不会考虑马基雅维利会这样做的可能性。本项研究更进一步的目 的则是要表明，对韦托里书信的重视不足如何会对[x] 理解马基 雅维利的书信乃至《君主论》的某些重要方面构成严重限制。 长期以来，人们对书信的解读之所以都是有限的和零散的，还 有一个原因，存在于一个人们最常承认却又鲜有研究的主题中：马 基雅维利与韦托里在对政治与外交事务的“严肃”讨论和对情爱 与性欲怪癖的“轻佻”打趣之间的交替有种难以理解的捉摸不定。 马基雅维利和韦托里并没有解释或者论证这些方向的中断或者改 变，而由此导致的一系列情绪、主题和语言的变化让很多读者有种 不适的感觉：两类论述( discorsi) 彼此之间少有关联甚至毫无关 联。尽管有过一些值得注意的努力，试图揭示谈论政治和谈论情 爱的书信之间可能的关联，但一般的倾向则是偏好其中一个而放 弃另一个。完全可以想见，历史学家们将其大部分的注意力投向 了谈论政治的书信，而文学批评家们则深挖谈论情爱的书信与马 基雅维利的喜剧之间的关系。这每一组书信都被用来阐释不同的</p><p>前 言 3</p><p>主要著作，而这也限制了一种发问的角度：为什么马基雅维利与韦 托里中断他们对政治的讨论转而开始一段明显怪诞的关于情爱的 交谈，尔后又回到政治上，但随后又折回情爱?这种跳转的驱动力 和马基雅维利与韦托里促成这种跳转的方式将是我对这些书信进 行分析的关键焦点。 除了一两处著名的例外，甚至连马基雅维利的书信，在或明或 暗的与那些“主要”著作对比之下，也面临着某种在文学体裁的等 级次序中被贬抑到次一级(有时甚至更低)地位的趋势。①正如第 一章将要表明的，对书信持蔑视态度的一种形式(这在文艺复兴 时期就非常有影响)来自一种经典的文学传统看法。根据这一看 法，书信不过是且应该不过是[xi] 落到纸面的随意的对话，用西塞 罗的著名说法就是把“那些说出来的”(quod inbuccam venerit)用 笔记录下来。这种惯常的看法在人文主义的书信写作中很流行， 马基雅维利肯定知道这一点，而且非常有可能的是，他在1513年 12月10日那封著名的信件中暗里提到了这一点：他在信中告诉 韦托里，《君主论》是他对在与古人对话(conversatione)中的有益</p><p>①不过，近来书信写作史和书信体研究开始逐渐成为出产重要研究成果的领域。有 关中世纪和文艺复兴文化中的书信体写作的导引，见 Giles Constable, Letters and Letter Collections,fasc. 17 of Typologie des sources du moyen age occidental,Turn- hout:Brepols, 1976。关于早期现代和现代文献中的书信体写作，见 Janet Gurkin Altman, Epistolarity,Approaches to a Form, Columbus,Ohio:Ohio University Press, 1982; 以 及 L&#39;e pistolarite a travers les siecles:Geste de communication etlou d&#39;ecriture, 这是1987年博西斯(Mireille Bossis)和波特( Charles A.Porter)在瑟里西 拉萨勒国际文化中心组织的学术会议文集(Stuttgart:Franz Steiner Verlag,1990)。 有关意大利文化中的书信体写作，见La correspondance [édition,fonctions,signifi cations] ,vol.I,Actes du colloque francoitalien,Aix-en-Provence,October 1983, Aix-en-Provence:Centre Aixois de Recherches Italiennes,1984,and vol.2,Actes du colloque international,Aix-en-Provence,October 1984,Aix-en-Provence:Centre Aixois de Recherches Italiennes,1985。对文艺复兴时期人文主义书信体写作的关 键性理解有重要贡献的是施特吕弗那本相当晚近的书(我完成本书之后才出版): Nancy S.Struever,Theory as Practice:Ethical Inquiry in the Renaissance, Chicago: University of Chicago Press,1992, 特别是第一章和第二章。</p><p>4 权力与欲望- 基雅维利与韦托里1513—1515年通信研究 内容的记录( io ho notato),是为那些不在对话现场的人写下 来的。 但是，正如我也要表明的，马基雅维利一定也同样清楚，从彼 特拉克到波利齐亚诺和伊拉斯谟，许多出色的人文主义者都批评 过这种传统的书信写作观念。因此本书的计划如下：首先对主要 的有关马基雅维利与韦托里书信的学术探究与阐释路线做一引 介，并且简要、初步地描述(和辩护)我自己的进路与方法，然后在 第一章考察文艺复兴时期书信写作极为流行背后文学和理论的难 题——写作与演说的关系，有关思想、意图、观点和说服之语言的 地位，以及这些问题与人文主义对对话、友谊与政治的强调之间的 关联。第二章为马基雅维利与韦托里的通信提供一个更为切近的 背景，不仅包括他们的友谊和他们政治生涯上关联的过往，还包括 马基雅维利在超过14年的国务秘书任上每天都在做的实实在在 的书信写作实践，而韦托里在这方面也有一些经验。实际上，后续 有关书信的各章的首要论点之一便是，韦托里有策略地利用了书 信这一体裁和书信体无法解决的诸种困境所带来的潜在的东西， 促使马基雅维利重新思考有关语言和写作的一些假定，他将这些 假定运用于政治论述，在1513年的书信中和在《君主论》中都是 如此，这些假定与那14年间的日常书信写作有着重要的关联。通 过这种方式，韦托里引导马基雅维利去面对某些关于语言和论述 的关键性议题，这些议题内嵌于人文主义书信写作技艺的实践与 悖论之中。</p><p>~***~ 本项研究缘起于一篇论文，它未曾发表但在一两个地方被引 用过(并冠以“因我之歌：马基雅维利论放逐”[ Per miei carmi: Machiavelli&#39;s Discourses of Exile]的标题，暗指马基雅维利对但丁 论放逐的《神曲 ·天国篇》第十七歌的思考),这是多年前我在康</p><p>前 言 5</p><p>奈尔大学人文学会担任研究员时写的。我要感谢学会为我提供了 自由，让我从那一年的正式研究项目中偷闲，能够在一群出色的同 仁和朋友们的陪伴下[ xii] 阅读和思考马基雅维利的书信，他们的 陪伴让我文思泉涌，十分愉快。那篇文章是提交给学会内部的一 次研讨会的，它部分得自于研讨会前次会议上的热烈讨论的结果。 我很感谢与这群长期分散各处的朋友共度美好的一年，感谢他们 对拙文慷慨而热烈的回应，他们一定都不记得这篇文章了。 只有在多年后我才想要试图以更严肃和更大的篇幅来处理原 来这篇出于兴趣和写给朋友们看的文章。我如此决定，部分是因 为那篇文章受到了来自许多卓越读者的鼓励与批评，包括坎波雷 亚莱(Salvatore Camporeale)、卡林顿( Laurel Carrington)、冈德斯 海默( Werner Gundersheimer)、古恩茨伯格( Lynn Gunzberg)、肯特 (Dale Kent)、拉扎罗( Claudia Lazzaro)、莫尔霍( Anthony Mol- ho)、龙多( Jennifer Rondeau)、韦 弗( Elissa Weaver),特别是斯金 纳( Quentin Skinner)和莫瑞斯(Ted Morris),他们使我确信依靠这 些丰富的文本还能够做出更多东西。当然，他们无需为我如何使 用他们给我的意见负责。在写作过程中，我接受了来自阿斯科利 ( Albert Ascoli)、安杰利斯( Laura De Angelis)、格拉齐尼( Filippo Grazzini)、雅考夫( Rachel Jacoff)、卢尼( Dennis Looney)、皮里洛 (Paolo Pirillo),以及安东尼奥( Antonio) 和雷娜( Marina Reina)一 家的慷慨帮助和诸多有益建议。我要特别感谢贝 斯 特( Myra Best), 我们有过很多关于马基雅维利的富有启发性的讨论，她对 第三至八章的草稿做了详细的和批判性的审读，并且这个研究项 目的很多方面都得到她的帮助。我要感谢布莱克( Robert Black)、 布朗( Alison Brown)、康奈尔(William Connell)和卡门( Michael Kammen)的好心，他们仔细地阅读了手稿并给出了丰富的评论。 每个人都让我免除了大量错误和不当之处，并在解决文本和历史 问题上给予我极大帮助。我也要感激奥斯本( Lauren Osborne),</p><p>6 权力与欲望——马基雅维利与韦托里1513—1515年通信研究 我的手稿在普林斯顿大学出版社得到她热情而高效的处理。我还 要感谢刘易斯( Gavin Lewis),他以其精专高超的编辑功力使文稿 在很多方面增色不少。最后要感谢的是佩利( Patricia Pelley),她 帮我解开了很多困惑，耐心地倾听许多含糊不清的猜测，并且以其 一贯不同寻常的犀利眼光审读了手稿的诸多章节，我要致以我最 热烈的感谢。 我用这本书纪念两位令我难忘的、时常思念的友人，我一直都 渴望将这项研究献给他们。我在完成本书的过程中收获的乐趣从 未因不能与他们二人探讨它而有丝毫减弱。</p><p>于伊萨卡岛和佛罗伦萨 1992 年</p><p>缩 写</p><p>Legazioni e commissarie Niccolò Machiavelli,Legazioni e commissarie,ed. Sergio Bertelli,3 vols.,Milan:Feltrinelli,1964 Lettere Niccolò Machiavelli, Lettere,Opere di Niccolò Mach- iavelli, vol.3,ed.Franco Gaeta,Turin:UTET, 1984 Lettere a FV Niccolò Machiavelli, Lettere a Francesco Vettori e a Francesco Guicciardini,ed.Giorgio Inglese,Milan: Rizzoli,1989 O pere Niccolò Machiavelli, Tutte le opere,ed.Mario Mar- telli,Florence:Sansoni,1971</p><p>Ridolfi, Vita di NM Roberto Ridolfi, Vita di Niccolò Machiavelli,7th ed., Florence:Sansoni,1978 Sasso,NM: storia del Gennaro Sasso, Niccolò Machiavelli:storia del suo suopensiero politico pensiero politico,2d rev.ed.,Bologna:l Mulino, 1980 Scritti di governo Niccolò Machiavelli,Legazioni,commissarie,scritti di governo,ed.Fredi Chiappelli and Jean-Jacques Marchand,4 vols.,Scrittori d&#39;Italia,vols.249,256, 271,272,Rome and Bari:G.Laterza,1971-1985 Tommasini,La vita e Oreste Tommasini,La vita e gli scritti di Niccolò gli scritti di NM Machiavelli, 2 vols.,Rome,Turin,and Florence: Ermanno Loescher,1883-1911 Vettori,Scritti storici e Francesco Vettori, Scriti storici e Politici, ed.Enrico politici Niccolini,Bari:G.Laterza,1972</p><p>导论书信在马基雅维利研究中的地位</p><p>[3]除了少数例外，马基雅维利与韦托里的书信通常(正如我 们将要看到的)被解读为，韦托里预见到意大利将遭到瑞士人的 蹂躏：瑞士人会偶尔突袭、劫掠富足的物资，然后，他们会舍弃意大 利转向附近更熟悉和更安全的高地。就像他认为瑞士人仅满足于 从意大利攫取他们需要的东西而绝不会直接控制意大利一样，人 们也匆匆掠视他们的书信而且还多数情况下只读马基雅维利的 信，产生了诸多重要的成果。但人们总是倾向于将这些书信当成 是其他叙事的附属品，也当作对其他解读的一种支持(极少情况 下是修正),以及用作其他目的。① 马基雅维利最重要的传记作家们在复原和出版这些书信上功 勋卓著,从19世纪和20世纪早期的维拉里( Villari) 和托马西尼 (Tommasini) 到较晚近的里多尔菲( Ridolfi) 。 他们也大量地使用</p><p>①本段开头提到的例外包括两本专著,一本总体论述马基雅维利的书信，另一本则着 眼于他与韦托里的通信，它们分别是O. Ferrara,The Private Correspondence of Niccolò Machiavelli,Baltimore:Johns Hopkins University Press,1929;Alfredo Moretti, Corrispondenza di Niccolò Machiavelli con Francesco Vettor dal 1513 al 1515,F lorence: Le Monnier,1948。但这两本书就当下标准而言，都批判性不足、 不像历史著作。</p><p>这些书信印证马基雅维利一生中的诸多事实，修订和商榷马基雅 维利的年表，指出他内心深处这样那样的部分，他的个人想法和感 情。①但是，这样一条进路并没有使得人们细读这些书信或者对 他们的对话产生太多兴趣。[4]政治思想史家们在运用这些书信 的时候一定程度上更具选择性，他们更多地关注那些最终出现在 主要著作中的政治观念，确定它们的起源和追寻它们的发展。特 别是马基雅维利1513年4月和8月的那两封信，它们就写在创作 《君主论》之前，已经成为此类分析的丰富源泉。出于此类目的对 这些书信最全面的和有价值的研究当属沙博( Federico Chabod)、 萨索( Gennaro Sasso)和多蒂(Ugo Dotti)的研究。②有关对解读和</p><p>①维拉里的《马基雅维利和他的时代》( Niccolò Machiavelli e i suoi tempi) 最 初 于 1877至1882年间以三卷本在佛罗伦萨莫尼耶(Le Monnier)出版社出版，之后作者 又扩展和修订重印了两次( Pasquale Villari,Milan:Hoepli,1895-1897 and 1912- 1914),特别是1912至1914年间的第三版，第212至第232页讨论了马基雅维利 与韦托里的通信(第四版是在作者死后的1927年出版的，由斯凯里洛[ Michele Scherillo] 编辑，只有两卷，去掉了文献附录)。维拉里将第一版译成一个英文的 “大众版”(1058页的两大卷!)书名是《马基雅维利的生平与时代》( Linda Villari, The Life and Times of Niccolo Machiavelli,New York:Charles Scribner&#39;s Sons, 1898),在第二卷的第43至第58页有一个对马基雅维利与韦托里的通信的概览。 托马西尼在《马基雅维利的生平与著作》(Oreste Tommasini,La vita e gli scritti di NM) 的第二卷第71至第88页讨论了他们的通信。里多尔菲在其关于马基雅维利 生平的权威记述《尼科洛 · 马基雅维利传》( Vita di NM)的第十三至第十五章关注 了这些书信。在里多尔菲著作的第二版( Roberto Ridolfi,Rome:A.Belardetti, 1954)的格雷森(Cecil Grayson)英译本《马基雅维利传》( The Life of Niccolò Machi- avelli, Chicago: University of Chicago Press,1963) 中，也是在第十三至第十五章讨 论了他们的通信，页码是第139至第162页。 ②关于沙博，特别参见1927年的论文《论马基雅维利《君主论&gt;的写作》( Federico Chabod,Sulla composizione de‘II Principe&#39;di Niccolò Machiavelli),收在他身后出 版的关于马基雅维利的论文集《马基雅维利的著作》( Federico Chabod, Scritti su Machiavelli, Turin:Einaud i,1964;reprinted.,1980,pp. 137-193)。 萨索则将他的 注意力集中在1513年的书信上，见他的《马基雅维利的政治思想史》( Gennaro Sas- so, NM:storia del suo pensiero politico)第五章“《君主论》的起源与结构”(Genesi e struttura del &#39;Principe&#39;,pp.293-335)。 多蒂出于类似的目的，对他们的通信给予了 相当重要的关注，参见Ugo Doti, Niccolo Machiavelli:Ia fenomenologia (转下页)</p><p>导论书信在马基雅维利研究中的地位 11 确定主要著作年代的更为具体问题的讨论也是对某些书信的重要 应用。① 在重现某种人们认为的马基雅维利及其“思想”的核心、本质 甚或总体的时候，1513年的一些书信发挥了重要的甚至是决定性 的作用。尤其有两封信帮助我们塑造了马基雅维利的当代形象 (或者说诸种当代形象中比较有影响的)。第一封是1513年4月 9日的信，其中马基雅维利在未来无望继续从事政治的情况下，告 诉韦托里“命中注定，我既不懂丝织和毛纺之事，也不懂赢利和亏 损之事，我必须谈论国家。我要么发誓保持沉默，要么谈论这 个”。第二封则是那封更为著名的1513年12月10日的信，在信 中，他为韦托里生动描述了他在佩尔库西纳的圣安德里亚的放逐 生活，以及他夜里同古人的谈话，并最终告知他正在创作一本关于 君主国的“小书”。这些文本着实已经成为经典文本，在构建[5] 解读和理解马基雅维利的一般性框架上的重要性仅次于某些文本 (也的确如此)——比如说，《君主论》第十五章的开头几行。在那</p><p>(接上页注②)del potere,Milan:Feltrinelli,1980, esp.pp. 17-52,100-106。 ①想要列出一个哪怕是具有代表性的此类研究的列表都是不可能的。最有趣和最有 价值的贡献属于巴龙和惠特菲尔德，围绕《君主论》和《李维史论》写作时间的难 题，巴龙的分析，参见Hans Baron,&quot;Machiavelli the Republican Citizen and Author of The Prince,” 首次发表于 English Historical Review 76,1961:217-253, 修订重版 收录于巴龙的In Search of Florentine Civic Humanism:Essays on the Transition from Medieval to Modern Thought,2 vols.,Princeton,N.J:Princeton University Press, 1988,2:pp.101-151, esp.pp. 134-142。 还有他身后发表的论文“The Principe and the Puzzle of the Date of Chapter 26,&quot;Joumal of Medieval and Renaissance Stud- ies 21,1991 pp.83-102。 另外参见惠特菲尔德对1513年8月的书信的分析《论 《君主论〉》( Whitfield,An Essay on The Prince),附在《君主论》查莱克特手稿 (Charlecote Manuscript of Ⅱ Principe,Wakefield,England:S.R.Publishers,Ltd.; Paris and The Hague:M outon ,1969) 摹本之前。费尔也在他具有争议性的重释马 基雅维利的政治观念和他与美第奇家族关系的著作( A.London Fell,Pre-modem &#39;Machiavellism,&#39; forthcoming,New York:Praeger,1993 as book 1 of volume 5 of his series on the Origins of Legislative Sovereignty and the Legislative State)中广泛使 用了马基雅维利与韦托里的书信。</p><p>12 权力与欲望- 基雅维利与韦托里1513—1515年通信研究 几行中，马基雅维利告诉他的读者们，他不像那些谈论共和国与君 主国的人那样只靠想象，他所追求的乃是他所谓的“有效的真 理”。1513年4月9日和12月10日的这两封信像此类著名的段 落一样，都启发人们思考这样一个问题：马基雅维利是否、如何，以 及同谁常常谈论政治和为政治写作。不过，即使是这两封信也都 像往常一样被孤立地解读、被从马基雅维利与韦托里连贯的通信 对话中摘取出来，它们也能够产生出很多意涵，可以与许多更广泛 的对马基雅维利的阐释相容。就这两封信而言，一个特别引人注 目的解读是：在这两封信中我们看到，马基雅维利在苦难和被罢黜 的岁月里迅速而自信地形成一些新的术语，他的新使命是要做一 位政治理论家。 把每封单独的书信和它们作为部分的书信对话打散开来，这 种倾向已经在多方面使得深入解读局限而又贫乏。第一个危险就 是，那些知道自己在探索什么的聪明读者通常会发现这一点。在 很多情况下，由于对通信的粗略探究是为了确定或修正对其他文 本的阐释，或者是要找到马基雅维利在主要著作中更完整阐发之 观念的起源，这种方法通常将注意力集中在——有时是完全集中 在——信件中那些能够达到这一目的的段落，通常会忽略掉其他 部分。这也制造或者强化了这样一种假定：马基雅维利的“思想” 存在根本性的统一或者一致，或者说他的诸多观念是渐次发展起 来的，至少在某种特定视角局限下的马基雅维利就是如此。马基 雅维利政治思想的研究者们都读过1513年春天和夏天有关阿拉 贡的斐迪南、教宗利奥十世以及瑞士人的信，他们将这些信当作某 种试验场，马基雅维利理论中的很多部分从这里出现并可以在 《君主论》中找到。在信中可以预见或者确认这些观念，这一发现 使得人们相信，马基雅维利在写《君主论》的时候(在某些人看来， 写《李维史论》的时候也同样如此),他的思想和方法的基本内容</p><p>已经成型，有待进一步详细扩展为统一、充分的论述。① 文学史家和评论家们对1514年初那些谈论爱情的书信很感 兴趣，[6]对他们文学上的试验和创新尤为注意，从而阐明了这部 分打趣的通信同马基雅维利的戏剧《曼陀罗》和《克莉齐娅》之间 的重要关联。②人们发现这些书信和戏剧在用词上、风格上和主 旨上存在连续性，从而充实了有关马基雅维利的文学才能、人文主 义训练以及他受惠于托斯卡纳方言传统等方面的观点。费罗尼和 雷蒙迪的作品是这类作品中最棒的。③从这种视角出发，至少对</p><p>①其中一个例子，见萨索对马基雅维利1513年4月29日书信与《君主论》关系的评 论：“如果，这看起来非常有可能，《君主论》是在1513年的7至12月写成的，那么 4月29日的信很清楚地表明在那个时刻，不仅仅[《君主论》的]基本概念，还有它 的结构和谋篇已经有了。 ”(NM:Storia del suo pensiero politico, pp.314-315.) 在</p>',30)])])}const v=i(n,[["render",l]]);export{u as __pageData,v as default};
